import { db } from './firebase-config.js';
import { collection, getDocs, deleteDoc, doc } from "firebase/firestore";

const recipesContainer = document.getElementById('recipes');
const recipeTemplate = document.getElementById('recipe-template');

async function loadAndDisplayData() {
    const querySnapshot = await getDocs(collection(db, "recipes"));

    querySnapshot.forEach((firebaseDoc) => {
        const data = firebaseDoc.data();

        const cloneTemplate = recipeTemplate.content.cloneNode(true);

        const titleElement = cloneTemplate.querySelector('.recipe-title');
        const descriptionElement = cloneTemplate.querySelector('.recipe-description');
        const ingredientsAmount = cloneTemplate.querySelector('.ingredients-count');
        const btnDelete = cloneTemplate.querySelector('.btn-delete');
        const openLink = cloneTemplate.querySelector('.btn-open');

        titleElement.textContent = data.title;
        descriptionElement.textContent = data.description;

        const ingredients = data.ingredients;
        const ingredientsLength = ingredients ? ingredients.length : 0;
        ingredientsAmount.textContent = "Інгредієнтів: " + ingredientsLength;

        openLink.href = `pages/recipe.html?id=${firebaseDoc.id}`;

        btnDelete.addEventListener("click", async function () {
            const isConfirmed = confirm(`Видалити рецепт "${data.title}"?`);

            if (isConfirmed) {
                await deleteDoc(doc(db, "recipes", firebaseDoc.id));

                const cardElement = btnDelete.closest('.recipe-card');
                cardElement.remove();
            }
        });

        recipesContainer.appendChild(cloneTemplate);
    });
}

loadAndDisplayData();